async function insertBatch(questions: Question[]): Promise<number> {
  let inserted = 0;
  const batchSize = 50;

  for (let i = 0; i < questions.length; i += batchSize) {
    const batch = questions.slice(i, i + batchSize);
    const values: string[] = [];
    const params: any[] = [];
    let idx = 1;

    for (const q of batch) {
      values.push(`($${idx},$${idx+1},$${idx+2},$${idx+3},$${idx+4},$${idx+5}::jsonb,$${idx+6}::jsonb,$${idx+7},$${idx+8}::integer,$${idx+9},$${idx+10},$${idx+11})`);
      params.push(q.tier, q.exam, q.questionType, q.status, q.stem, JSON.stringify(q.options), JSON.stringify(q.correctAnswer), q.rationale, q.difficulty, q.bodySystem, q.regionScope, q.stemHash);
      idx += 12;
    }

    const sql = `INSERT INTO exam_questions (tier, exam, question_type, status, stem, options, correct_answer, rationale, difficulty, body_system, region_scope, stem_hash)
                 SELECT v.* FROM (VALUES ${values.join(",")}) AS v(tier,exam,question_type,status,stem,options,correct_answer,rationale,difficulty,body_system,region_scope,stem_hash)
                 WHERE NOT EXISTS (SELECT 1 FROM exam_questions e WHERE e.stem_hash = v.stem_hash)`;

    const result = await pool.query(sql, params);
    inserted += result.rowCount || 0;
  }
  return inserted;
}

async function main() {
  console.log(`[Seed] Starting tier question seeding...`);
  console.log(`[Seed] RPN questions to insert: ${RPN_QUESTIONS.length}`);
  console.log(`[Seed] RN questions to insert: ${RN_QUESTIONS.length}`);
  console.log(`[Seed] NP questions to insert: ${NP_QUESTIONS.length}`);

  const rpnInserted = await insertBatch(RPN_QUESTIONS);
  console.log(`[Seed] RPN: inserted ${rpnInserted} new questions`);

  const rnInserted = await insertBatch(RN_QUESTIONS);
  console.log(`[Seed] RN: inserted ${rnInserted} new questions`);

  const npInserted = await insertBatch(NP_QUESTIONS);
  console.log(`[Seed] NP: inserted ${npInserted} new questions`);

  const counts = await pool.query(`SELECT tier, count(*) as cnt FROM exam_questions WHERE status='published' GROUP BY tier ORDER BY tier`);
  console.log(`\n[Seed] Final published counts:`);
  counts.rows.forEach((r: any) => console.log(`  ${r.tier}: ${r.cnt}`));

  await pool.end();
  console.log(`[Seed] Done.`);
}

main().catch(e => { console.error(e); process.exit(1); });
